export const title = "Testing";
export const description = "Configure Jest to work with React Native Vector Icons";
export const body = "Configure Jest to mock native font loading and prevent errors in your test suite.\n\n## Jest Configuration\n\nWhen running tests with `jest`, you need to mock out the native code loading to prevent errors.\n\n### 1. Add moduleNameMapper for TTF files\n\nIn your `jest.config.js`, add a module name mapper to intercept `.ttf` imports:\n\n```js\n// jest.config.js\nmodule.exports = {\n  // ...other config\n  moduleNameMapper: {\n    '\\\\.(ttf)$': '<rootDir>/__mocks__/file-mock.js',\n  },\n}\n```\n\n### 2. Create the file mock\n\nCreate `__mocks__/file-mock.js`:\n\n```js\n// __mocks__/file-mock.js\nmodule.exports = {};\n```\n\n### 3. Mock the common library\n\nCreate `__mocks__/@react-native-vector-icons/common.js` to prevent native module loading errors:\n\n```js\n// __mocks__/@react-native-vector-icons/common.js\nmodule.exports = {\n  createIconSet: () => \"icon\",\n};\n```\n\n> [!TIP]\n> With these three files in place, Jest will be able to run your tests without encountering native font loading errors. The TTF mapper redirects font imports to an empty module, and the common library mock replaces `createIconSet` with a no-op.";
